import React, { useEffect } from 'react';
import { Link } from 'react-router-dom';
import M from 'materialize-css';

const Navbar = ({ theme, toggleTheme }) => {
  useEffect(() => {
    // Initialize sidenav
    const elems = document.querySelectorAll('.sidenav');
    M.Sidenav.init(elems);
  }, []);

  return (
    <>
      <nav>
        <div className="nav-wrapper container" style={{ display: 'flex', alignItems: 'center', padding: '0 2rem', minHeight: '64px' }}>
          <Link to="/" className="brand-logo" style={{ marginRight: '3rem', fontSize: '2rem' }}>MakerSpace</Link>
          <ul className="right hide-on-med-and-down" style={{ display: 'flex', alignItems: 'center', gap: '2.5rem', margin: 0, padding: 0, listStyle: 'none', flex: 1, justifyContent: 'center' }}>
            <li><Link to="/" className="waves-effect">Home</Link></li>
            <li><Link to="/about" className="waves-effect">About</Link></li>
            <li><Link to="/contact" className="waves-effect">Contact</Link></li>
          </ul>
          <div style={{ marginLeft: 'auto', marginRight: '1rem', display: 'flex', alignItems: 'center' }}>
            <div className="switch theme-switch">
              <label style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: 0 }}>
                <i className="material-icons">wb_sunny</i>
                <input 
                  type="checkbox" 
                  id="theme-toggle" 
                  checked={theme === 'dark'} 
                  onChange={toggleTheme}
                />
                <span className="lever"></span>
                <i className="material-icons">brightness_3</i>
              </label>
            </div>
          </div>
          <a href="#!" data-target="mobile-nav" className="sidenav-trigger" style={{ marginLeft: '1.5rem' }}>
            <i className="material-icons">menu</i>
          </a>
        </div>
      </nav>

      <ul className="sidenav" id="mobile-nav">
        <li><Link to="/" className="waves-effect">Home</Link></li>
        <li><Link to="/about" className="waves-effect">About</Link></li>
        <li><Link to="/contact" className="waves-effect">Contact</Link></li>
        <li>
          <div className="switch theme-switch">
            <label>
              <i className="material-icons">wb_sunny</i>
              <input 
                type="checkbox" 
                id="theme-toggle-mobile" 
                checked={theme === 'dark'} 
                onChange={toggleTheme}
              />
              <span className="lever"></span>
              <i className="material-icons">brightness_3</i>
            </label>
          </div>
        </li>
      </ul>
    </>
  );
};

export default Navbar;
